const writeRunLogEffect = (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): BackendEffect<void> =>
  Effect.gen(function*() {
    const filePath = path.join(runsPath(projectPath), ticketId, `${runId}.jsonl`);
