import type { ClarificationQuestionCreateInput } from "../../shared/types";

type RawQuestion = string | { question?: unknown; text?: unknown; answerType?: unknown };

const parseQuestion = (value: RawQuestion): ClarificationQuestionCreateInput | null => {
  if (typeof value === "string") {
    const question = value.trim();
    return question ? { question, answerType: "text" } : null;
  }

  const rawQuestion = typeof value.question === "string" ? value.question : typeof value.text === "string" ? value.text : "";
  const question = rawQuestion.trim();
  if (!question) return null;
  return { question, answerType: "text" };
};

const parseQuestionsJson = (value: string): ClarificationQuestionCreateInput[] => {
  const parsed = JSON.parse(value) as unknown;
  const rawQuestions = Array.isArray(parsed)
    ? parsed
    : typeof parsed === "object" && parsed !== null && Array.isArray((parsed as { questions?: unknown }).questions)
      ? (parsed as { questions: unknown[] }).questions
      : [];

  return rawQuestions
    .map((question) => parseQuestion(question as RawQuestion))
    .filter((question): question is ClarificationQuestionCreateInput => Boolean(question))
    .slice(0, 10);
};

export const extractClarificationRequest = (finalResponse: string): ClarificationQuestionCreateInput[] => {
  const questions: ClarificationQuestionCreateInput[] = [];
  const fencePattern = /```relay-clarification\s*([\s\S]*?)```/gi;
  let match: RegExpExecArray | null;

  while ((match = fencePattern.exec(finalResponse))) {
    const json = match[1]?.trim();
    if (!json) continue;
    try {
      questions.push(...parseQuestionsJson(json));
    } catch {
      continue;
    }
  }

  return questions;
};

import { contextBridge, ipcRenderer } from "electron";
import type {
  AgentTicketUpdateInput,
  ClarificationAnswerInput,
  CreateDraftInput,
  EpicSubticketCreateInput,
  EpicSubticketLinkInput,
  EpicSubticketUnlinkInput,
  GitMetadataOptions,
  RelayApi,
  RelayApprovalDecision,
  RendererRunEvent,
  StartRunInput,
  TicketCreateInput,
  TicketMoveInput,
  TicketSaveInput
} from "../shared/types";

const api: RelayApi = {
  projects: {
    list: () => ipcRenderer.invoke("projects:list"),
    addFolder: () => ipcRenderer.invoke("projects:addFolder"),
    removeFromSidebar: (projectPath: string) => ipcRenderer.invoke("projects:removeFromSidebar", projectPath),
    read: (projectPath: string) => ipcRenderer.invoke("projects:read", projectPath),
    gitMetadata: (projectPath: string, options?: GitMetadataOptions) => ipcRenderer.invoke("projects:gitMetadata", projectPath, options),
    revealInFinder: (projectPath: string) => ipcRenderer.invoke("projects:revealInFinder", projectPath)
  },
  board: {
    read: (projectPath: string) => ipcRenderer.invoke("board:read", projectPath)
  },
  ticket: {
    createDraft: (input: CreateDraftInput) => ipcRenderer.invoke("ticket:createDraft", input),
    createManual: (projectPath: string, input: TicketCreateInput) => ipcRenderer.invoke("ticket:createManual", projectPath, input),
    createSubticket: (input: EpicSubticketCreateInput) => ipcRenderer.invoke("ticket:createSubticket", input),
    linkSubticket: (input: EpicSubticketLinkInput) => ipcRenderer.invoke("ticket:linkSubticket", input),
    unlinkSubticket: (input: EpicSubticketUnlinkInput) => ipcRenderer.invoke("ticket:unlinkSubticket", input),
    startAgentUpdate: (input: AgentTicketUpdateInput) => ipcRenderer.invoke("ticket:startAgentUpdate", input),
    cancelAgentUpdate: (runId: string) => ipcRenderer.invoke("ticket:cancelAgentUpdate", runId),
    references: (projectPath: string) => ipcRenderer.invoke("ticket:references", projectPath),
    read: (projectPath: string, ticketId: string) => ipcRenderer.invoke("ticket:read", projectPath, ticketId),
    save: (input: TicketSaveInput) => ipcRenderer.invoke("ticket:save", input),
    move: (input: TicketMoveInput) => ipcRenderer.invoke("ticket:move", input),
    clarifications: (projectPath: string, ticketId: string) => ipcRenderer.invoke("ticket:clarifications", projectPath, ticketId),
    answerClarification: (input: ClarificationAnswerInput) => ipcRenderer.invoke("ticket:answerClarification", input),
    delete: (projectPath: string, ticketId: string) => ipcRenderer.invoke("ticket:delete", projectPath, ticketId),
    duplicate: (projectPath: string, ticketId: string) => ipcRenderer.invoke("ticket:duplicate", projectPath, ticketId),
    revealFile: (projectPath: string, ticketId: string) => ipcRenderer.invoke("ticket:revealFile", projectPath, ticketId)
  },
  codex: {
    status: () => ipcRenderer.invoke("codex:status"),
    startRun: (input: StartRunInput) => ipcRenderer.invoke("codex:startRun", input),
    resumeRun: (input: StartRunInput) => ipcRenderer.invoke("codex:resumeRun", input),
    cancelRun: (runId: string) => ipcRenderer.invoke("codex:cancelRun", runId),
    approveAction: (approvalId: string, decision: RelayApprovalDecision) => ipcRenderer.invoke("codex:approveAction", approvalId, decision),
    readRunEvents: (projectPath: string, ticketId: string, runId: string) =>
      ipcRenderer.invoke("codex:readRunEvents", projectPath, ticketId, runId),
    onRunEvent: (listener: (event: RendererRunEvent) => void) => {
      const wrapped = (_event: Electron.IpcRendererEvent, payload: RendererRunEvent): void => listener(payload);
      ipcRenderer.on("codex:runEvent", wrapped);
      return () => ipcRenderer.removeListener("codex:runEvent", wrapped);
    }
  }
};

contextBridge.exposeInMainWorld("relay", api);

export type ClarificationQuestionCreateInput = {
  question: string;
  answerType?: ClarificationAnswerType;
};

export type ClarificationAnswerInput = {
  projectPath: string;
  ticketId: string;
  questionId: string;
  answer: string;
};

export type RelayAuditEvent = {
  schemaVersion: number;
  timestamp: string;
  actor: RelayActor;
  source: RelayEventSource;
  eventType: "ticket.status_changed" | "clarification.question_created" | "clarification.answer_submitted";
  ticketId?: string;
  runId?: string | null;
  payload: Record<string, unknown>;
};

export type AddProjectResult = {
  project: ProjectSummary;
  initialized: boolean;
};

export type AppRegistry = {
  schemaVersion: number;
  projects: Array<{
    path: string;
    pinned: boolean;
    lastOpenedAt: string;
    sidebarPosition: number;
  }>;
  ui: {
    lastProjectPath: string | null;
    theme: ThemePreference;
  };
};

export type RelayCodexEvent =
  | { type: "run.started"; runId: string; threadId: string; timestamp: string }
  | { type: "agent.message.delta"; text: string; timestamp: string }
  | { type: "agent.message.completed"; text: string; timestamp: string }
  | { type: "command.started"; command: string; cwd?: string; timestamp: string }
  | { type: "command.output"; stream: "stdout" | "stderr"; text: string; timestamp: string }
  | { type: "command.completed"; status: "completed" | "failed" | "declined"; timestamp: string }
  | { type: "file.change"; path: string; summary?: string; timestamp: string }
  | { type: "web.search"; query: string; timestamp: string }
  | { type: "approval.requested"; approvalId: string; kind: "command" | "file-change" | "network" | "other"; payload: unknown; timestamp: string }
  | { type: "approval.resolved"; approvalId: string; decision: string; timestamp: string }
  | { type: "ticket.status_changed"; fromStatus: string; toStatus: string; actor: RelayActor; source: RelayEventSource; timestamp: string }
  | { type: "clarification.requested"; questions: ClarificationQuestion[]; timestamp: string }
  | { type: "run.completed"; finalResponse: string; usage?: unknown; timestamp: string }
  | { type: "run.failed"; message: string; details?: unknown; timestamp: string };

export type RendererRunEvent = RelayCodexEvent & {
  projectPath: string;
  ticketId: string;
  runId: string;
};

export type RelayApprovalDecision = "accept" | "acceptForSession" | "decline" | "cancel";

export type CodexStatus = {
  sdkAvailable: boolean;
  cliAvailable: boolean;
  cliVersion: string | null;
  authenticated: boolean | null;
  message: string;
};

export type StartRunInput = {
  projectPath: string;
  ticketId: string;
  freshThread?: boolean;
};

export type CreateDraftInput = {
  projectPath: string;
  idea: string;
  preferredTicketType?: TicketType;
};

export type RunLogLine = {
  schemaVersion: number;
  timestamp: string;
  ticketId: string;
  runId: string;
  threadId: string;
  type: RelayCodexEvent["type"];
  payload: Record<string, unknown>;
};

export type RelayApi = {
  projects: {
    list: () => Promise<ProjectSummary[]>;
    addFolder: () => Promise<AddProjectResult | null>;
    removeFromSidebar: (projectPath: string) => Promise<ProjectSummary[]>;
    read: (projectPath: string) => Promise<ProjectSummary>;
    gitMetadata: (projectPath: string, options?: GitMetadataOptions) => Promise<GitMetadata>;
    revealInFinder: (projectPath: string) => Promise<void>;
  };
  board: {
    read: (projectPath: string) => Promise<BoardSnapshot>;
  };
  ticket: {
    createDraft: (input: CreateDraftInput) => Promise<TicketDraftResult>;
    createManual: (projectPath: string, input: TicketCreateInput) => Promise<TicketRecord>;
    createSubticket: (input: EpicSubticketCreateInput) => Promise<TicketRecord>;
    linkSubticket: (input: EpicSubticketLinkInput) => Promise<BoardSnapshot>;
    unlinkSubticket: (input: EpicSubticketUnlinkInput) => Promise<BoardSnapshot>;
    startAgentUpdate: (input: AgentTicketUpdateInput) => Promise<AgentTicketUpdateStartResult>;
    cancelAgentUpdate: (runId: string) => Promise<void>;
    references: (projectPath: string) => Promise<TicketReferenceCandidate[]>;
    read: (projectPath: string, ticketId: string) => Promise<TicketRecord>;
    save: (input: TicketSaveInput) => Promise<TicketRecord>;
    move: (input: TicketMoveInput) => Promise<BoardSnapshot>;
    clarifications: (projectPath: string, ticketId: string) => Promise<ClarificationQuestion[]>;
    answerClarification: (input: ClarificationAnswerInput) => Promise<ClarificationQuestion>;
    delete: (projectPath: string, ticketId: string) => Promise<BoardSnapshot>;
    duplicate: (projectPath: string, ticketId: string) => Promise<TicketRecord>;
    revealFile: (projectPath: string, ticketId: string) => Promise<void>;
  };
  codex: {
    status: () => Promise<CodexStatus>;
    startRun: (input: StartRunInput) => Promise<{ runId: string; threadId: string }>;
    resumeRun: (input: StartRunInput) => Promise<{ runId: string; threadId: string }>;
    cancelRun: (runId: string) => Promise<void>;
    approveAction: (approvalId: string, decision: RelayApprovalDecision) => Promise<void>;
    readRunEvents: (projectPath: string, ticketId: string, runId: string) => Promise<RendererRunEvent[]>;
    onRunEvent: (listener: (event: RendererRunEvent) => void) => () => void;
  };
};

